css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #fff0f7; color: #2d1b2e; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 48px; height: 64px; background: white; border-bottom: 1px solid #fce7f3; position: sticky; top: 0; z-index: 100; }
.logo { font-size: 20px; font-weight: 800; color: #be185d; font-style: italic; }
.links { display: flex; gap: 24px; } .links a { color: #9ca3af; text-decoration: none; font-size: 14px; font-weight: 500; } .links a:hover { color: #be185d; }
.nav-right { display: flex; align-items: center; gap: 12px; }
.nav-icon { font-size: 20px; cursor: pointer; }
.cart-wrap { position: relative; cursor: pointer; font-size: 22px; }
.cart-badge { position: absolute; top: -6px; right: -6px; width: 18px; height: 18px; border-radius: 50%; background: #ec4899; color: white; font-size: 10px; font-weight: 800; display: flex; align-items: center; justify-content: center; }
.hero { display: grid; grid-template-columns: 1fr 1fr; gap: 48px; align-items: center; padding: 64px 48px; background: linear-gradient(160deg, #fff0f7, #fce7f3); }
.hero-tag { display: inline-block; color: #be185d; font-size: 13px; font-weight: 700; margin-bottom: 16px; }
h1 { font-size: 64px; font-weight: 900; line-height: 1; letter-spacing: -2px; margin-bottom: 16px; color: #2d1b2e; } h1 em { font-style: italic; color: #ec4899; }
.hero-text p { color: #9ca3af; font-size: 16px; line-height: 1.7; margin-bottom: 24px; max-width: 400px; }
.hero-btns { display: flex; gap: 12px; }
.btn-shop { padding: 14px 28px; border-radius: 30px; border: none; background: linear-gradient(135deg, #ec4899, #be185d); color: white; font-weight: 800; font-size: 15px; cursor: pointer; }
.btn-quiz { padding: 14px 24px; border-radius: 30px; border: 1px solid #fce7f3; background: transparent; color: #be185d; font-weight: 600; font-size: 14px; cursor: pointer; }
.product-showcase { }
.ps-main { height: 260px; border-radius: 24px; background: linear-gradient(135deg, #fce7f3, #fbcfe8, #f9a8d4); display: flex; align-items: center; justify-content: center; font-size: 80px; position: relative; margin-bottom: 14px; }
.ps-label { position: absolute; bottom: 16px; left: 16px; right: 16px; background: white; border-radius: 14px; padding: 12px 16px; display: flex; justify-content: space-between; align-items: center; font-size: 15px; font-weight: 700; color: #2d1b2e; } .ps-label span { color: #ec4899; font-weight: 900; }
.ps-mini-list { display: flex; gap: 10px; }
.ps-mini { flex: 1; background: white; border-radius: 14px; padding: 14px; text-align: center; border: 1px solid #fce7f3; } .ps-mini span { display: block; font-size: 11px; color: #9ca3af; margin-top: 6px; }
.categories { padding: 48px; } .categories h2 { font-size: 28px; font-weight: 800; margin-bottom: 24px; }
.cat-grid { display: grid; grid-template-columns: repeat(4,1fr); gap: 16px; }
.cat-card { background: white; border-radius: 18px; padding: 24px; text-align: center; cursor: pointer; transition: all 0.2s; border: 1px solid #fce7f3; } .cat-card:hover, .cat-card.active { border-color: #ec4899; transform: translateY(-3px); box-shadow: 0 8px 20px rgba(236,72,153,0.12); }
.cc-img { font-size: 36px; margin-bottom: 10px; } .cat-card strong { display: block; font-size: 15px; font-weight: 700; color: #2d1b2e; } .cat-card span { color: #9ca3af; font-size: 12px; }
.products { padding: 0 48px 48px; }
.products-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; } .products-header h2 { font-size: 24px; font-weight: 800; }
.see-all { color: #ec4899; text-decoration: none; font-weight: 600; font-size: 14px; }
.products-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); gap: 16px; }
.product-card { background: white; border-radius: 18px; overflow: hidden; border: 1px solid #fce7f3; transition: all 0.2s; cursor: pointer; } .product-card:hover { transform: translateY(-4px); box-shadow: 0 8px 24px rgba(236,72,153,0.12); }
.pc-img { height: 180px; display: flex; align-items: center; justify-content: center; font-size: 60px; }
.pc-info { padding: 14px; } .pc-cat { font-size: 11px; font-weight: 700; color: #ec4899; letter-spacing: 1px; margin-bottom: 4px; } .pc-name { font-size: 14px; font-weight: 700; color: #2d1b2e; margin-bottom: 4px; } .pc-brand { font-size: 12px; color: #9ca3af; margin-bottom: 10px; } .pc-row { display: flex; justify-content: space-between; align-items: center; } .pc-price { font-size: 17px; font-weight: 900; color: #be185d; } .pc-add { width: 32px; height: 32px; border-radius: 50%; border: none; background: #ec4899; color: white; font-size: 18px; cursor: pointer; display: flex; align-items: center; justify-content: center; }
.cart-drawer { position: fixed; right: -380px; top: 0; width: 380px; height: 100vh; background: white; z-index: 200; transition: right 0.3s; display: flex; flex-direction: column; box-shadow: -4px 0 20px rgba(0,0,0,0.1); }
.cart-drawer.open { right: 0; }
.overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.4); z-index: 199; display: none; } .overlay.open { display: block; }
.drawer-head { display: flex; justify-content: space-between; align-items: center; padding: 20px; border-bottom: 1px solid #fce7f3; } .drawer-head h3 { font-size: 18px; font-weight: 800; color: #2d1b2e; } .drawer-head button { width: 32px; height: 32px; border-radius: 50%; border: none; background: #fce7f3; cursor: pointer; font-size: 16px; }
.drawer-items { flex: 1; overflow-y: auto; padding: 16px; }
.di { display: flex; gap: 12px; align-items: center; padding: 12px 0; border-bottom: 1px solid #fef2f8; }
.di-em { font-size: 28px; } .di-info { flex: 1; } .di-info strong { display: block; font-size: 14px; color: #2d1b2e; } .di-info span { color: #ec4899; font-weight: 700; } .di-rm { background: none; border: none; color: #ec4899; cursor: pointer; font-size: 18px; }
.drawer-foot { padding: 16px; border-top: 1px solid #fce7f3; } .foot-total { display: flex; justify-content: space-between; margin-bottom: 12px; font-size: 15px; color: #2d1b2e; } .foot-total strong { font-size: 20px; font-weight: 900; color: #be185d; }
.checkout-btn { width: 100%; height: 50px; border-radius: 25px; border: none; background: linear-gradient(135deg, #ec4899, #be185d); color: white; font-size: 15px; font-weight: 800; cursor: pointer; }

