const products = [
  {id:1,name:'Glow Serum',brand:'Lumière',price:480,cat:'cilt',emoji:'✨',bg:'#fce7f3,#fbcfe8'},
  {id:2,name:'Kırmızı Ruj',brand:'Rouge Paris',price:185,cat:'makyaj',emoji:'💄',bg:'#fee2e2,#fecaca'},
  {id:3,name:'Rose Water',brand:'Lumière',price:220,cat:'cilt',emoji:'🌹',bg:'#fdf2f8,#fce7f3'},
  {id:4,name:'Floral EDP',brand:'Belle',price:680,cat:'parfum',emoji:'🌺',bg:'#fdf4ff,#f3e8ff'},
  {id:5,name:'Saç Maskesi',brand:'Silk',price:340,cat:'sac',emoji:'💆',bg:'#fef3c7,#fde68a'},
  {id:6,name:'BB Krem',brand:'Lumière',price:290,cat:'makyaj',emoji:'✨',bg:'#fff7ed,#fed7aa'},
  {id:7,name:'Nemlendirici',brand:'Hydra+',price:380,cat:'cilt',emoji:'💧',bg:'#eff6ff,#bfdbfe'},
  {id:8,name:'Oud Parfüm',brand:'Orient',price:920,cat:'parfum',emoji:'🎋',bg:'#f0fdf4,#bbf7d0'}
];
let cart = [], currentCat = 'all';
function renderProducts() {
  const visible = currentCat === 'all' ? products : products.filter(p => p.cat === currentCat);
  document.getElementById('products').innerHTML = visible.map(p => `
    <div class='product-card'>
      <div class='pc-img' style='background:linear-gradient(135deg,${p.bg})'>${p.emoji}</div>
      <div class='pc-info'>
        <div class='pc-cat'>${p.cat.toUpperCase()}</div>
        <div class='pc-name'>${p.name}</div>
        <div class='pc-brand'>${p.brand}</div>
        <div class='pc-row'><span class='pc-price'>₺${p.price.toLocaleString('tr')}</span><button class='pc-add' onclick='addCart(${p.id})'>+</button></div>
      </div>
    </div>
  `).join('');
}
function addCart(id) {
  const p = products.find(p => p.id === id);
  const ex = cart.find(c => c.id === id);
  if (ex) ex.qty++; else cart.push({...p, qty:1});
  updateCart();
}
function removeCart(id) { cart = cart.filter(c => c.id !== id); updateCart(); }
function updateCart() {
  document.getElementById('badge').textContent = cart.reduce((s,c)=>s+c.qty,0);
  const total = cart.reduce((s,c)=>s+c.price*c.qty,0);
  document.getElementById('total').textContent = '₺'+total.toLocaleString('tr');
  document.getElementById('drawer-items').innerHTML = cart.length===0 ? '<p style="text-align:center;color:#9ca3af;padding:40px">Çantanız boş 🛍️</p>' : cart.map(c=>`<div class='di'><span class='di-em'>${c.emoji}</span><div class='di-info'><strong>${c.name} x${c.qty}</strong><span>₺${(c.price*c.qty).toLocaleString('tr')}</span></div><button class='di-rm' onclick='removeCart(${c.id})'>×</button></div>`).join('');
}
function toggleCart() { document.getElementById('drawer').classList.toggle('open'); document.getElementById('overlay').classList.toggle('open'); }
function filterCat(cat, card) { currentCat = cat; document.querySelectorAll('.cat-card').forEach(c=>c.classList.remove('active')); card.classList.add('active'); renderProducts(); }
renderProducts();
